package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract class representing a Python node used to generate objects of a certain type.
 * Each node represents a domain of possible values and can generate exhaustive or random values.
 *
 * @param <T> the type of Python object generated by this node
 */
public abstract class APyNode<T extends APyObj> {

    /**
     * The exhaustive domain specification for this node.
     */
    protected List<Integer> exDomain;

    /**
     * The random domain specification for this node.
     */
    protected List<Integer> ranDomain;

    /**
     * Returns the exhaustive domain for this node.
     *
     * @return the exhaustive domain for this node
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param exDomain the exhaustive domain to set
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Returns the random domain for this node.
     *
     * @return the random domain for this node
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the random domain for this node.
     *
     * @param ranDomain the random domain to set
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Generates all exhaustive values for this node based on its exhaustive domain.
     *
     * @return a set of all exhaustive values for this node
     */
    public abstract Set<T> genExVals();

    /**
     * Generates a single random value for this node based on its random domain.
     *
     * @return a single random value for this node
     */
    public abstract T genRandVal();
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.HashSet;
import java.util.List;
import java.util.Random;
import java.util.Set;

/**
 * A class representing a Python node for generating integer objects.
 */
public class PyIntNode extends APyNode<PyIntObj> {

    /**
     * Generates all exhaustive values for this node based on its exhaustive domain.
     * For PyIntNode, the domain specification is a list of integers to be generated.
     *
     * @return a set of all exhaustive values for this node
     */
    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> results = new HashSet<>();
        for (Integer val : this.exDomain) {
            results.add(new PyIntObj(val));
        }
        return results;
    }

    /**
     * Generates a single random value for this node based on its random domain.
     *
     * @return a single random value for this node
     */
    @Override
    public PyIntObj genRandVal() {
        if (this.ranDomain == null || this.ranDomain.isEmpty()) {
            return null;
        }
        int randomIndex = new Random().nextInt(this.ranDomain.size());
        return new PyIntObj(this.ranDomain.get(randomIndex));
    }
}

