/**
 * Generates a combined list of test cases including all exhaustive ones and
 * then adding the specified number of random ones (avoiding duplicates from
 * the exhaustive ones).
 *
 * @param numRand the number of random test cases to generate
 * @return a list of all test cases
 */
public List<TestCase> genTests(int numRand) {
    Set<TestCase> exTests = this.genExTests();
    List<TestCase> baseSet = new ArrayList<>(exTests);
    Set<TestCase> allTests = new HashSet<>(exTests);

    int attempts = 0;
    int added = 0;
    while (added < numRand && attempts < 1000) {
        List<APyObj> args = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            args.add(node.genRandVal());
        }
        TestCase randomCase = new TestCase(args);
        if (!allTests.contains(randomCase)) {
            baseSet.add(randomCase);
            allTests.add(randomCase);
            added++;
        }
        attempts++;
    }

    return baseSet;
}
